mapper.select:
SELECT COUNT(*)
FROM EQUIPMENT E


	E.EQ_USAGE = 'Y'


		AND E.EQ_WPID = #{eqWpid}



	    AND E.EQ_STATUS IN

	        #{status}




	    AND E.EQ_STATUS = #{eqStatus}



		AND (
		UPPER(E.EQ_ID) LIKE UPPER('%' || #{searchKeyword} || '%')
		OR UPPER(E.EQ_NAME) LIKE UPPER('%' || #{searchKeyword} || '%')
		)

SELECT COUNT(*)
FROM EQ_RUN_LOG
WHERE EQ_RUN_EQID = #{eqId}

mapper.update:
UPDATE EQ_RUN_LOG
SET
EQ_RUN_ETIME = SYSDATE,
EQ_STOP_REASON = #{eqStopReason}
WHERE EQ_RUN_EQID = #{eqId}
AND EQ_RUN_ETIME IS NULL

UPDATE EQUIPMENT
SET
EQ_NAME = #{eqName},
EQ_VENDOR = #{eqVendor},
EQ_MANAGER = #{eqManager}


	, EQ_WPID = #{eqWpid}


WHERE EQ_ID = #{eqId}

UPDATE EQUIPMENT
SET EQ_STATUS = #{eqStatus}
WHERE EQ_ID = #{eqId}

UPDATE EQUIPMENT
SET EQ_USAGE = 'N'
WHERE EQ_ID = #{eqId}
